const orders = [
  { id: 1, user: 'Alex', price: 100 },
  { id: 2, user: 'John', price: 200 },
  { id: 3, user: 'Alex', price: 300 },
  { id: 4, user: 'Kate', price: 150 },
  { id: 5, user: 'John', price: 50 },
];

Array.prototype.allPrice = function () {
  return this.reduce((totals, curr) => {
    if (!totals[curr.user]) {
      totals[curr.user] = 0;
    }

    totals[curr.user] += curr.price;
    console.log(totals);
    return totals;
  }, {});
};
console.log(orders.allPrice());
//console.log(allPrice(orders, 'price'));

const orders2 = [
  { id: 1, userId: 1, total: 100, status: 'paid' },
  { id: 2, userId: 2, total: 50, status: 'pending' },
  { id: 3, userId: 1, total: 70, status: 'paid' },
  { id: 4, userId: 3, total: 200, status: 'paid' },
  { id: 5, userId: 2, total: 30, status: 'paid' },
  { id: 6, userId: 1, total: 20, status: 'pending' },
];

function groupOrdersByUser(orders) {
  return orders.reduce((total, curr) => {
    if (!total[curr.userId]) {
      total[curr.userId] = {
        userId: curr.userId,
        totalPaid: 0,
        totalPaiding: 0,
        orderCount: 0,
      };
    }
    if (total[curr.userId].userId === curr.userId && curr.status === 'paid') {
      total[curr.userId].totalPaid += curr.total;
    } else {
      total[curr.userId].totalPaiding += curr.total;
    }
    if (total[curr.userId].userId === curr.userId) {
      total[curr.userId].orderCount++;
    }

    return total;
  }, {});
}
console.log(groupOrdersByUser(orders2));
